// Procesar CSV de FRED — GFDEBTN: Total Public Debt Outstanding (millones USD)
// Formato CSV: DATE,GFDEBTN\n2024-01-01,34001234\n...
const csv = items[0].json.data || items[0].json.body || '';

if (!csv || typeof csv !== 'string') {
  return [{ json: { error: 'Sin datos FRED', timestamp: new Date().toISOString() } }];
}

const lines = csv.trim().split('\n').filter(l => l && !l.startsWith('DATE'));

// Tomar las últimas 3 observaciones (mensuales)
const recientes = lines.slice(-3).map(line => {
  const [fecha, valor] = line.split(',');
  return {
    fecha: fecha?.trim(),
    deuda_millones_usd: parseFloat(valor?.trim() || 0)
  };
});

const ultimo = recientes[recientes.length - 1];
const anterior = recientes[recientes.length - 2];

const cambio_mensual_mm = ultimo && anterior
  ? ((ultimo.deuda_millones_usd - anterior.deuda_millones_usd) / 1000).toFixed(1)
  : null;

const deuda_trillones = ultimo ? (ultimo.deuda_millones_usd / 1e6).toFixed(3) : null;

const resultado = {
  agente: 'EAGLE',
  fuente: 'FRED — GFDEBTN (Federal Reserve St. Louis)',
  indicador: 'Total Public Debt Outstanding USA',
  ultima_fecha: ultimo?.fecha,
  deuda_millones_usd: ultimo?.deuda_millones_usd,
  deuda_legible: `$${deuda_trillones}T USD`,
  cambio_mensual_miles_mm: cambio_mensual_mm,
  tendencia: cambio_mensual_mm > 0 ? '⬆️ Deuda aumentando' : '⬇️ Deuda disminuyendo',
  alerta: ultimo?.deuda_millones_usd > 33_000_000 ? '⚠️ Deuda >$33T USD' : '✅ Dentro de rango',
  historico_3m: recientes,
  timestamp: new Date().toISOString()
};

console.log('[EAGLE]', JSON.stringify(resultado, null, 2));
return [{ json: resultado }];
